import { useEffect, useMemo } from 'react';
import { Globe } from 'lucide-react';
import { useTranslation } from 'react-i18next';

const LANGS = [
  { code: 'en', label: 'EN' },
  { code: 'fr', label: 'FR' },
  { code: 'ar', label: 'AR' },
] as const;

export function LanguageSwitcher() {
  const { i18n, t } = useTranslation();

  const current = useMemo(() => {
    const normalized = (i18n.resolvedLanguage || i18n.language || 'fr').split('-')[0];
    return (LANGS.find((l) => l.code === normalized) ?? LANGS[1]).code;
  }, [i18n.language, i18n.resolvedLanguage]);

  useEffect(() => {
    const lang = (i18n.resolvedLanguage || i18n.language || 'fr').split('-')[0];
    const dir = lang === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
    document.documentElement.dir = dir;
  }, [i18n.language, i18n.resolvedLanguage]);

  return (
    <div className="flex items-center gap-2">
      <Globe size={18} className="text-[#6B7280]" />
      <select
        aria-label={t('nav.applications')}
        value={current}
        onChange={(e) => i18n.changeLanguage(e.target.value)}
        className="text-sm bg-transparent border border-[#E5E7EB] rounded-md px-2 py-1 text-[#374151]"
      >
        {LANGS.map((l) => (
          <option key={l.code} value={l.code}>
            {l.label}
          </option>
        ))}
      </select>
    </div>
  );
}

