export function ProductCardsSection() {
	const { t } = useTranslation();

	return (
		<section className="os-product-section py-20 px-6">
			<div className="max-w-[1200px] mx-auto">
				{/* Section Title */}
				<motion.h2
					initial={{ opacity: 0, y: 20 }}
					whileInView={{ opacity: 1, y: 0 }}
					viewport={{ once: true }}
					transition={{ duration: 0.5, ease: 'easeOut' }}
					className="os-product-title"
				>
					{t('home.products.title')}
				</motion.h2>

				{/* 3 Product Cards */}
				<div className="os-product-grid">
					{products.map((product) => (
						<motion.div
							key={product.id}
							initial={{ opacity: 0, y: 30 }}
							whileInView={{ opacity: 1, y: 0 }}
							whileHover={{ y: -8, scale: 1.02 }}
							viewport={{ once: true }}
							transition={{ duration: 0.2, ease: 'easeOut' }}
							className="os-card"
						>
							{/* Card Top - Screenshot Area */}
							<div
								className="os-media"
								style={{
									padding: `${product.imagePadding}px`,
								}}
							>
								<img
									src={product.image}
									alt={t(product.imageAltKey)}
									className="os-mediaImage os-mediaImage--contained"
									style={{
										objectFit: product.imageFit,
										objectPosition: product.imagePosition,
										maxWidth: `${product.imageMaxWidth}px`,
										margin: '0 auto',
										borderRadius: '14px',
										boxShadow: '0 14px 30px rgba(0,0,0,0.10)',
										background: 'transparent',
									}} 
								/>

								{/* Soft gradient for readability */}
								<div className="os-mediaOverlay" />

								{/* Floating Icon Badges (equal circles) */}
								{product.badges.map((badge, i) => (
									<div key={i} className={`os-badge ${badge.position}`}>
										<badge.icon size={18} className="os-badgeIcon" />
									</div>
								))}
							</div>

							{/* Card Bottom - Text Area */}
							<div className="os-cardBody">
								<h3 className="os-cardTitle">{t(product.titleKey)}</h3>
								<p className="os-cardDesc">{t(product.descriptionKey)}</p>

								<div className="os-cardFooter">
									<button className="os-cardCta">
										{t(product.buttonKey)}
										<ArrowRight size={16} />
									</button>
								</div>
							</div>
						</motion.div>
					))}
				</div>
			</div>
		</section>
	);
}

/* SolutionHero - floating image cards */

.solution-hero-cards {
  position: relative;
  height: 640px; /* a bit taller to give more breathing room */
}

.solution-hero-card {
  position: absolute;
  overflow: hidden;

  border-radius: 14px;
  background: rgba(255, 255, 255, 0.86);
  border: 1px solid rgba(255, 255, 255, 0.55);

  box-shadow:
    0 18px 48px rgba(0, 0, 0, 0.14),
    0 1px 0 rgba(255, 255, 255, 0.35) inset;

  -webkit-backdrop-filter: blur(10px);
  backdrop-filter: blur(10px);
}

.solution-hero-card--lg {
  width: 320px;
  height: 210px;
}

.solution-hero-card--md {
  width: 300px;
  height: 205px;
}

.solution-hero-card--phone {
  width: 165px;
  height: 290px;
  border-radius: 22px;
}

.solution-hero-card__img {
  width: 100%;
  height: 100%;
  display: block;

  object-fit: cover;
  object-position: center;

  /* Make screenshots look premium */
  transform: scale(1.02);
  filter: contrast(1.03) saturate(1.06);
  transition: transform 260ms ease, filter 260ms ease;
}

.solution-hero-card:hover .solution-hero-card__img {
  transform: scale(1.06);
  filter: contrast(1.06) saturate(1.12);
}

.solution-hero-card__shine {
  position: absolute;
  inset: 0;
  pointer-events: none;
  background: linear-gradient(
    135deg,
    rgba(255, 255, 255, 0.34) 0%,
    rgba(255, 255, 255, 0.05) 42%,
    rgba(0, 0, 0, 0.08) 100%
  );
  opacity: 0.7;
}

.solution-hero-card__badge {
  position: absolute;
  left: 12px;
  bottom: 12px;
  padding: 8px 12px;
  border-radius: 10px;

  font-family: Inter, sans-serif;
  font-weight: 700;
  font-size: 12px;

  letter-spacing: 0.2px;
  box-shadow: 0 10px 22px rgba(0, 0, 0, 0.18);
  border: 1px solid rgba(255, 255, 255, 0.18);
}

.solution-hero-card__badge--green {
  color: #fff;
  background: linear-gradient(135deg, rgba(45, 71, 44, 0.96), rgba(45, 71, 44, 0.55));
}

.solution-hero-card__badge--gold {
  color: #2D472C;
  background: linear-gradient(135deg, rgba(197, 160, 89, 0.96), rgba(197, 160, 89, 0.55));
}

@media (max-width: 1024px) {
  .solution-hero-cards {
    height: 560px;
  }
  .solution-hero-card--lg {
    width: 290px;
    height: 195px;
  }
  .solution-hero-card--md {
    width: 270px;
    height: 190px;
  }
  .solution-hero-card--phone {
    width: 155px;
    height: 270px;
  }
}

@media (max-width: 640px) {
  .solution-hero-cards {
    height: 520px;
  }
}

