      navigate('/login');
    } else {
      loadContactMessagesCount();
      loadDashboard();
      loadDemoRequests();
    }
  }, []);

  const loadDashboard = async () => {
    setLoadingStats(true);
    setApiError(null);
    try {
      const data = await apiGet<DashboardStatsDTO>('/api/analytics/dashboard');
      setStats(data);
      loadDemoRequests();
    } catch (e: any) {
      setApiError(e?.message ?? 'Erreur API');
      setStats(null);
