  border: 1px solid rgba(45, 71, 44, 0.16);

  background:
    radial-gradient(120% 120% at 0% 0%, rgba(197, 160, 89, 0.20) 0%, rgba(255, 255, 255, 0) 55%),
    linear-gradient(135deg, rgba(45, 71, 44, 0.12), rgba(197, 160, 89, 0.10));

  box-shadow: 0 18px 48px rgba(0, 0, 0, 0.10);

  /*
    Make the block follow the image proportions.
    Update these numbers if c1.png has a different ratio.
  */
  aspect-ratio: 4 / 3;
  height: auto;

  /* keep it reasonable on very small/large screens */
  min-height: 280px;
  max-height: 520px;
}

/* Fallback for browsers without aspect-ratio support */
@supports not (aspect-ratio: 1 / 1) {
  .contact-hero-media {
    height: 420px;
  }
}

.contact-hero-media__img {
  position: absolute;
